import torch
import torch.nn as nn
import torch.optim as optim
from torch.utils.data import Dataset, DataLoader
import torchvision.transforms as transforms
from torchvision import models
import requests
from io import BytesIO

class CustomDataset(Dataset):
    def __init__(self, data, labels):
        self.data = data
        self.labels = labels

    def __len__(self):
        return len(self.data)

    def __getitem__(self, idx):
        return self.data[idx], self.labels[idx]

class ModelTuner:
    def __init__(self, 
                 pretrained_model_urls: list,
                 train_dataset: Dataset,
                 val_dataset: Dataset,
                 num_epochs: int=5,
                 batch_size: int=64,
                 learning_rate: float=0.001):

        self.models = self.download_and_load_models(pretrained_model_urls)
        self.train_dataset = train_dataset
        self.val_dataset = val_dataset
        self.num_epochs = num_epochs
        self.batch_size = batch_size
        self.learning_rate = learning_rate
        self.device = torch.device("cuda:0" if torch.cuda.is_available() else "cpu")

    def download_and_load_models(self, urls):
        models = []
        for url in urls:
            response = requests.get(url)
            checkpoint = torch.load(BytesIO(response.content))
            model = models.resnet50(pretrained=False)
            model.load_state_dict(checkpoint)
            models.append(model)
        return models

    def fine_tune_model(self, model):
        dataloaders = {
            'train': DataLoader(self.train_dataset, batch_size=self.batch_size, shuffle=True),
            'val': DataLoader(self.val_dataset, batch_size=self.batch_size, shuffle=True)
        }

        criterion = nn.CrossEntropyLoss()
        optimizer = optim.SGD(model.parameters(), lr=self.learning_rate, momentum=0.9)
        model = model.to(self.device)

        for epoch in range(self.num_epochs):
            for phase in ['train', 'val']:
                if phase == 'train':
                    model.train()
                else:
                    model.eval()

                running_loss = 0.0
                running_corrects = 0

                for inputs, labels in dataloaders[phase]:
                    inputs = inputs.to(self.device)
                    labels = labels.to(self.device)

                    optimizer.zero_grad()

                    with torch.set_grad_enabled(phase == 'train'):
                        outputs = model(inputs)
                        _, preds = torch.max(outputs, 1)
                        loss = criterion(outputs, labels)

                        if phase == 'train':
                            loss.backward()
                            optimizer.step()

                    running_loss += loss.item() * inputs.size(0)
                    running_corrects += torch.sum(preds == labels.data)

                epoch_loss = running_loss / len(dataloaders[phase].dataset)
                epoch_acc = running_corrects.double() / len(dataloaders[phase].dataset)
        return model

    def tune_all_models(self):
        for model in self.models:
            self.fine_tune_model(model)

